sql:
SELECT name
FROM starships
WHERE status = 'operational';

SELECT SUM(CAST(REPLACE(REPLACE(cargo_capacity, ',', ''), ' kg', '') AS REAL)) AS total_cargo_capacity
FROM starships
WHERE status = 'operational';

SELECT name, cost_in_credits
FROM starships
ORDER BY cost_in_credits DESC;

SELECT AVG(cost_in_credits) AS average_cost
FROM starships
WHERE status = 'operational';

external_knowledge:
- 'under maintenance' implies the starships are not fully operational or are being repaired;
- 'overseeing this upkeep' refers to the technicians performing maintenance tasks on the starships;
- 'roles' indicate the job positions such as 'maintenance engineer' for those overseeing the maintenance.

